Here's how to save/restore draft text using MAUI's lifecycle events and `Preferences`:

**In your `NotePage.xaml.cs`:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();
        // Restore draft on page creation
        NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();
        // Subscribe to lifecycle events
        App.Current.Windows[0].Deactivated += OnAppBackground;
        App.Current.Windows[0].Resumed += OnAppResumed;
    }

    protected override void OnDisappearing()
    {
        base.OnDisappearing();
        App.Current.Windows[0].Deactivated -= OnAppBackground;
        App.Current.Windows[0].Resumed -= OnAppResumed;
    }

    private void OnAppBackground(object sender, EventArgs e)
    {
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void OnAppResumed(object sender, EventArgs e)
    {
        // Only restore if editor is empty (avoid overwriting active edits)
        if (string.IsNullOrEmpty(NoteEditor.Text))
            NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    // Call this when the user explicitly saves/discards
    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }
}
```

**Key points:**

- **`Deactivated`** fires when the app goes to background — save here.
- **`Resumed`** fires when the app returns to foreground.
- **`Preferences`** persists across app restarts (backed by `SharedPreferences`/`NSUserDefaults`).
- Unsubscribe in `OnDisappearing` to avoid leaks.
- Call `ClearDraft()` when the user saves or discards the note intentionally.

For large text, swap `Preferences` for `File.WriteAllTextAsync` to a path from `FileSystem.AppDataDirectory`.
